public abstract class Relation
{
	public List<int>? Emit { get; set; }

	[MemberNotNullWhen(true, "Emit")]
	public bool EmitSet
	{
		[MemberNotNullWhen(true, "Emit")]
		get
		{
			return Emit != null;
		}
	}

	public abstract int OutputLength { get; }

	public Hint Hint { get; set; } = new Hint();

	public abstract TReturn Accept<TReturn, TState>(RelationVisitor<TReturn, TState> visitor, TState state);

	public override bool Equals(object? obj)
	{
		if (obj is Relation relation)
		{
			if (Emit == null && relation.Emit != null)
			{
				return false;
			}
			if (Emit != null && relation.Emit == null)
			{
				return false;
			}
			if (Emit != null && relation.Emit != null && !Emit.SequenceEqual(relation.Emit))
			{
				return false;
			}
			if (!Hint.Equals(relation.Hint))
			{
				return false;
			}
			return true;
		}
		return false;
	}

	public override int GetHashCode()
	{
		HashCode hashCode = default(HashCode);
		if (Emit != null)
		{
			foreach (int item in Emit)
			{
				hashCode.Add(item);
			}
		}
		return hashCode.ToHashCode();
	}
}
